"""ExecutionHook Protocol."""

from __future__ import annotations

from typing import Any, Protocol, runtime_checkable


@runtime_checkable
class ExecutionHook(Protocol):
    async def before_node(self, node: Any, inputs: dict[str, Any]) -> dict[str, Any]: ...
    async def after_node(self, node: Any, result: dict[str, Any]) -> None: ...
    async def on_complete(self, results: dict[str, Any]) -> None: ...
